import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useMutation } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { Loader2, ShieldCheck, CreditCard } from "lucide-react";

const formSchema = z.object({
  name: z.string().min(2, "Name must be at least 2 characters"),
  email: z.string().email("Invalid email address"),
  phone: z.string().min(10, "Invalid phone number"),
  couponCode: z.string().optional(),
});

interface CustomerDetailsModalProps {
  isOpen: boolean;
  onClose: () => void;
  planName: string;
  category: string;
  amount: number;
}

declare global {
  interface Window {
    Razorpay: any;
  }
}

export function CustomerDetailsModal({ isOpen, onClose, planName, category, amount }: CustomerDetailsModalProps) {
  const { toast } = useToast();
  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: { name: "", email: "", phone: "", couponCode: "" },
  });

  const couponWatch = form.watch("couponCode");
  const [discount, setDiscount] = useState(0);

  const coupons: Record<string, number> = {
    'SAVE20': 0.20,
    'OFF10': 0.10,
  };

  const currentCoupon = couponWatch?.toUpperCase();
  const discountRate = currentCoupon ? coupons[currentCoupon] : 0;
  const discountAmount = amount * discountRate;
  const finalAmount = amount - discountAmount;

  const workerUrl = "https://sindhu-varma-worker.gauravgoodreads.workers.dev";

  const createOrderMutation = useMutation({
    mutationFn: async (data: any) => {
      const res = await fetch(`${workerUrl}/api/payment/create-order`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...data,
          customerName: data.name,
          customerEmail: data.email,
          customerPhone: data.phone,
          couponCode: data.couponCode
        }),
      });
      if (!res.ok) {
        const errData = await res.json();
        console.error("Order Creation Failed:", errData);
        throw new Error(errData.details || "Failed to create order");
      }
      return res.json();
    },
  });

  async function onSubmit(values: z.infer<typeof formSchema>) {
    try {
      const response = await createOrderMutation.mutateAsync({
        ...values,
        planName,
        category,
        amount,
      });

      const options = {
        key: response.keyId,
        amount: response.amount,
        currency: "INR",
        name: "Mentoria",
        description: `Booking for ${planName}`,
        order_id: response.id,
        handler: async function (paymentResponse: any) {
          try {
            const res = await fetch(`${workerUrl}/api/payment/verify`, {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                ...paymentResponse,
              }),
            });
            if (res.ok) {
              toast({ title: "Payment Successful!", description: "Your mentorship booking has been confirmed." });
              onClose();
            } else {
              throw new Error("Verification failed");
            }
          } catch (err) {
            toast({ title: "Payment Verification Failed", variant: "destructive" });
          }
        },
        prefill: {
          name: values.name,
          email: values.email,
          contact: values.phone,
        },
        theme: { color: "#6d28d9" },
      };

      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (error) {
      toast({ title: "Error", description: "Failed to initiate payment. Please try again.", variant: "destructive" });
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[450px] p-0 overflow-hidden border-0 shadow-2xl rounded-3xl">
        <div className="bg-primary p-8 text-white relative">
          <div className="absolute top-0 right-0 p-8 opacity-10">
            <CreditCard className="w-24 h-24" />
          </div>
          <DialogTitle className="text-2xl font-serif font-bold mb-2">Finalize Your Booking</DialogTitle>
          <DialogDescription className="text-white/80 text-base">
            You are booking the <span className="font-bold text-white">{planName}</span>
          </DialogDescription>
        </div>

        <div className="p-8 bg-card">
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <FormField
                control={form.control}
                name="name"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-xs font-bold uppercase tracking-widest text-foreground/50">Full Name</FormLabel>
                    <FormControl>
                      <Input placeholder="Enter your name" className="h-12 bg-background border-primary/10 rounded-xl focus:border-primary transition-all" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <div className="grid grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="email"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-xs font-bold uppercase tracking-widest text-foreground/50">Email</FormLabel>
                      <FormControl>
                        <Input placeholder="your@email.com" className="h-12 bg-background border-primary/10 rounded-xl focus:border-primary transition-all" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="phone"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-xs font-bold uppercase tracking-widest text-foreground/50">Phone</FormLabel>
                      <FormControl>
                        <Input placeholder="+91..." className="h-12 bg-background border-primary/10 rounded-xl focus:border-primary transition-all" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="couponCode"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-xs font-bold uppercase tracking-widest text-foreground/50">Coupon Code (Optional)</FormLabel>
                    <FormControl>
                      <div className="flex gap-2">
                        <Input 
                          placeholder="e.g. SAVE20" 
                          className="h-12 bg-background border-primary/10 rounded-xl focus:border-primary transition-all font-mono uppercase" 
                          {...field} 
                        />
                      </div>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <div className="pt-4 space-y-4">
                <div className="flex flex-col gap-2 p-4 bg-primary/5 rounded-2xl border border-primary/10">
                  <div className="flex items-center justify-between">
                    <span className="text-foreground/60 font-medium">Subtotal</span>
                    <span className="font-semibold">₹{amount.toLocaleString()}</span>
                  </div>
                  {discountAmount > 0 && (
                    <div className="flex items-center justify-between text-green-600">
                      <span className="text-sm font-medium">Discount ({currentCoupon})</span>
                      <span className="font-semibold">-₹{discountAmount.toLocaleString()}</span>
                    </div>
                  )}
                  <div className="h-px bg-primary/10 my-1" />
                  <div className="flex items-center justify-between">
                    <span className="text-foreground/80 font-bold">Total Amount</span>
                    <span className="text-2xl font-bold text-primary">₹{finalAmount.toLocaleString()}</span>
                  </div>
                </div>

                <Button
                  type="submit"
                  className="w-full h-14 text-base font-bold rounded-2xl shadow-xl shadow-primary/20 group relative overflow-hidden"
                  disabled={createOrderMutation.isPending}
                >
                  {createOrderMutation.isPending ? (
                    <Loader2 className="h-5 w-5 animate-spin" />
                  ) : (
                    <>
                      Proceed to Secure Payment
                      <ShieldCheck className="ml-2 h-5 w-5 group-hover:scale-110 transition-transform" />
                    </>
                  )}
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-700" />
                </Button>
                
                <p className="text-[10px] text-center text-foreground/40 italic">
                  Payments are securely processed via Razorpay. By proceeding, you agree to our terms of service.
                </p>
              </div>
            </form>
          </Form>
        </div>
      </DialogContent>
    </Dialog>
  );
}
